INSERT INTO ui_translations (key, locale, value) VALUES
  ('nav.memory_book', 'it', 'Perché la tua famiglia ha bisogno di un Libro dei Ricordi'),
  ('mb_page.eyebrow', 'it', 'Libro dei Ricordi'),
  ('mb_page.hero_title', 'it', 'Tutto ciò che un assistente deve sapere — in un unico posto'),
  ('mb_page.hero_body', 'it', 'Quando arriva un nuovo assistente, non dovrebbe dover indovinare. Il Libro dei Ricordi cattura chi è la tua persona cara, chi chiamare, cosa osservare e cosa le porta conforto — condiviso istantaneamente con tutti nel tuo team di cura.'),
  ('mb_page.hero_cta_primary', 'it', 'Crea il tuo Libro dei Ricordi'),
  ('mb_page.hero_cta_secondary', 'it', 'Accedi'),
  ('mb_page.mock_title', 'it', 'Scopri come appare il Libro dei Ricordi'),
  ('mb_page.mock_subtitle', 'it', 'Un profilo di cura dinamico che ogni membro del tuo team può vedere nel momento in cui si unisce.'),
  ('mb_page.mock_book_title', 'it', 'Libro dei Ricordi'),
  ('mb_page.mock_tab_overview', 'it', 'Panoramica'),
  ('mb_page.mock_tab_identity', 'it', 'Identità'),
  ('mb_page.mock_tab_contacts', 'it', 'Contatti'),
  ('mb_page.mock_tab_medical', 'it', 'Medico'),
  ('mb_page.mock_tab_prefs', 'it', 'Preferenze'),
  ('mb_page.mock_identity_heading', 'it', 'Identità e Profilo'),
  ('mb_page.mock_identity_sub', 'it', 'Dettagli personali di Margherita H.'),
  ('mb_page.mock_edit_btn', 'it', 'Modifica'),
  ('mb_page.mock_field_preferred_name', 'it', 'Nome Preferito'),
  ('mb_page.mock_field_address', 'it', 'Come Rivolgersi'),
  ('mb_page.mock_field_birthplace', 'it', 'Luogo di Nascita'),
  ('mb_page.mock_field_rel_status', 'it', 'Stato Civile'),
  ('mb_page.mock_field_cultural', 'it', 'Origine Culturale'),
  ('mb_page.mock_field_language', 'it', 'Preferenze Linguistiche'),
  ('mb_page.mock_field_about', 'it', 'Chi Sono'),
  ('mb_page.mock_about_text', 'it', 'Margherita ha trascorso 30 anni come insegnante di scuola a Edimburgo prima di emigrare con il suo defunto marito Giacomo. Ha un senso dell''umorismo caldo e asciutto e un profondo amore per i cruciverba, una buona tazza di tè e le storie dei suoi nipoti.'),
  ('mb_page.mock_progress_label', 'it', 'Progressi del Libro dei Ricordi'),
  ('mb_page.mock_sections', 'it', 'sezioni complete'),
  ('mb_page.benefits_title', 'it', 'Perché le famiglie si affidano al Libro dei Ricordi'),
  ('mb_page.benefits_subtitle', 'it', 'I team di cura funzionano meglio quando tutti hanno le stesse informazioni fin dal primo giorno.'),
  ('mb_page.benefit1_title', 'it', 'Contesto di cura immediato'),
  ('mb_page.benefit1_body', 'it', 'Qualsiasi nuovo assistente — un sostituto, un fratello in visita dall''estero — arriva con tutto ciò di cui ha bisogno per fornire buone cure fin dal primo momento.'),
  ('mb_page.benefit2_title', 'it', 'Niente più ricerca di numeri'),
  ('mb_page.benefit2_body', 'it', 'Ogni familiare, medico e contatto di emergenza in un unico posto. Trova la persona giusta in secondi, non in minuti.'),
  ('mb_page.benefit3_title', 'it', 'Passaggi di consegne più sicuri'),
  ('mb_page.benefit3_body', 'it', 'Note mediche, allergie e considerazioni di cura sempre a portata di mano. Transizioni informate significano meno lacune e meno rischi.'),
  ('mb_page.benefit4_title', 'it', 'Dignità personale'),
  ('mb_page.benefit4_body', 'it', 'Oltre ai fatti clinici, il Libro dei Ricordi cattura la persona — la sua storia, le sue preferenze, ciò che le porta gioia. La cura diventa più del semplice completamento di compiti.'),
  ('mb_page.features_title', 'it', 'Quattro sezioni. Un quadro completo.'),
  ('mb_page.features_subtitle', 'it', 'Ogni sezione è progettata attorno a momenti reali di cura — passaggi di consegne, emergenze, nuovi membri del team e cura quotidiana.'),
  ('mb_page.feat_identity_title', 'it', 'Identità e Profilo Personale'),
  ('mb_page.feat_identity_body', 'it', 'Cattura chi è la tua persona cara — non solo il suo nome, ma la sua storia. Questa sezione aiuta ogni assistente a connettersi con la persona dietro il piano di cura.'),
  ('mb_page.feat_identity_f1', 'it', 'Nome preferito e come gli piace essere chiamato'),
  ('mb_page.feat_identity_f2', 'it', 'Luogo di nascita e origine culturale'),
  ('mb_page.feat_identity_f3', 'it', 'Stato civile'),
  ('mb_page.feat_identity_f4', 'it', 'Preferenze linguistiche e comunicative'),
  ('mb_page.feat_identity_f5', 'it', 'Sintesi personale — con parole sue'),
  ('mb_page.feat_contacts_title', 'it', 'Rete di Cura e Contatti'),
  ('mb_page.feat_contacts_body', 'it', 'Memorizza ogni persona nella rete di supporto della tua persona cara — famiglia, medici, specialisti e contatti di emergenza — ognuno con il suo ruolo, telefono, email e note.'),
  ('mb_page.feat_contacts_f1', 'it', 'Familiari e loro relazione'),
  ('mb_page.feat_contacts_f2', 'it', 'Contatti del medico di base e degli specialisti'),
  ('mb_page.feat_contacts_f3', 'it', 'Vicini e supporto comunitario'),
  ('mb_page.feat_contacts_f4', 'it', 'Etichette di ruolo: assistente principale, emergenza, medico, altro'),
  ('mb_page.feat_medical_title', 'it', 'Contesto Medico'),
  ('mb_page.feat_medical_body', 'it', 'Non una cartella clinica — un riferimento pratico per assistenti. Documenta ciò che gli assistenti domiciliari e familiari hanno realmente bisogno di sapere per fornire cure sicure e fiduciose.'),
  ('mb_page.feat_medical_f1', 'it', 'Condizioni principali e diagnosi'),
  ('mb_page.feat_medical_f2', 'it', 'Allergie (alimentari, farmacologiche, ambientali)'),
  ('mb_page.feat_medical_f3', 'it', 'Note su udito e vista'),
  ('mb_page.feat_medical_f4', 'it', 'Farmaci attuali e note di somministrazione'),
  ('mb_page.feat_medical_f5', 'it', 'Altre considerazioni sanitarie per gli assistenti'),
  ('mb_page.feat_prefs_title', 'it', 'Preferenze, Avversioni e Conforti'),
  ('mb_page.feat_prefs_body', 'it', 'I dettagli che trasformano la cura da funzionale a personale. Sapere cosa calma, cosa evitare e cosa provoca un sorriso genuino rende ogni interazione migliore.'),
  ('mb_page.feat_prefs_f1', 'it', 'Attività, argomenti ed esperienze che apprezzano'),
  ('mb_page.feat_prefs_f2', 'it', 'Preferenze alimentari e cose da evitare'),
  ('mb_page.feat_prefs_f3', 'it', 'Preferenze musicali e argomenti di conversazione preferiti'),
  ('mb_page.feat_prefs_f4', 'it', 'Cosa li conforta quando sono turbati'),
  ('mb_page.feat_prefs_f5', 'it', 'Preferenze sensoriali e fattori scatenanti di angoscia'),
  ('mb_page.access_title', 'it', 'Costruito per il team. Visibile a tutti.'),
  ('mb_page.access_body', 'it', 'Il proprietario del team crea il Libro dei Ricordi. Ogni assistente che inviti — familiari, lavoratori domiciliari o persone di supporto — può vederlo nel momento in cui si unisce, senza configurazione richiesta.'),
  ('mb_page.access_cta', 'it', 'Crea il tuo Account Gratuito'),
  ('mb_page.access_plans', 'it', 'Visualizza Piani e Prezzi'),
  ('mb_page.personas_title', 'it', 'Chi beneficia del Libro dei Ricordi'),
  ('mb_page.personas_subtitle', 'it', 'Dall''assistente notturno che arriva per la prima volta al fratello che chiede notizie dall''estero.'),
  ('mb_page.persona1_title', 'it', 'L''assistente sostituto notturno'),
  ('mb_page.persona1_quote', 'it', '"Prima temevo di sostituire per una famiglia che non conoscevo. Ora controllo il Libro dei Ricordi prima di arrivare."'),
  ('mb_page.persona1_b1', 'it', 'Conosce le routine preferite e i conforti notturni prima di entrare'),
  ('mb_page.persona1_b2', 'it', 'Può trovare i contatti di emergenza senza svegliare nessuno'),
  ('mb_page.persona1_b3', 'it', 'Comprende le esigenze dei farmaci dalla prima notte'),
  ('mb_page.persona2_title', 'it', 'Il fratello che torna dall''estero'),
  ('mb_page.persona2_quote', 'it', '"Visito due volte all''anno e mi sento come uno straniero. Il Libro dei Ricordi colma quel divario."'),
  ('mb_page.persona2_b1', 'it', 'Si aggiorna sul contesto medico senza un lungo briefing familiare'),
  ('mb_page.persona2_b2', 'it', 'Sa cosa piace alla Mamma ora rispetto a un anno fa'),
  ('mb_page.persona2_b3', 'it', 'Può intervenire e aiutare con fiducia dal primo giorno'),
  ('mb_page.persona3_title', 'it', 'L''assistente principale'),
  ('mb_page.persona3_quote', 'it', '"Io sono la banca della memoria. Il Libro dei Ricordi significa che non devo spiegare tutto ogni volta."'),
  ('mb_page.persona3_b1', 'it', 'Documenta tutto una volta — non una dozzina di volte'),
  ('mb_page.persona3_b2', 'it', 'Condivide il peso della cura senza perdere il controllo dell''accuratezza'),
  ('mb_page.persona3_b3', 'it', 'Riduce il carico emotivo della comunicazione costante'),
  ('mb_page.persona4_title', 'it', 'Il medico di base o infermiere comunitario'),
  ('mb_page.persona4_quote', 'it', '"Le famiglie che arrivano organizzate ci aiutano a fornire cure migliori."'),
  ('mb_page.persona4_b1', 'it', 'Gli assistenti arrivano agli appuntamenti con note mediche chiare e aggiornate'),
  ('mb_page.persona4_b2', 'it', 'Allergie e condizioni sono documentate, non supposte'),
  ('mb_page.persona4_b3', 'it', 'I contatti sono disponibili per conversazioni di cura coordinate'),
  ('mb_page.faq_title', 'it', 'Domande Frequenti'),
  ('mb_page.faq_subtitle', 'it', 'Domande comuni sulla funzione Libro dei Ricordi.'),
  ('mb_page.faq1_q', 'it', 'Cos''è il Libro dei Ricordi e chi può vederlo?'),
  ('mb_page.faq1_a', 'it', 'Il Libro dei Ricordi è un profilo di cura strutturato per la tua persona cara, che copre identità, contatti, contesto medico e preferenze personali. Fa parte del tuo piano Family Circle di CarerView. Il proprietario del team lo crea e aggiorna. Ogni membro del team che inviti può vedere il Libro dei Ricordi completo non appena si unisce — senza configurazione aggiuntiva richiesta.'),
  ('mb_page.faq2_q', 'it', 'Ho bisogno del piano Family Circle per usare il Libro dei Ricordi?'),
  ('mb_page.faq2_a', 'it', 'Sì. Il Libro dei Ricordi è una funzione di team disponibile nel piano Family Circle. È progettato per essere condiviso — quindi ha più senso quando hai almeno un altro assistente o familiare nel tuo team che beneficia di vedere le stesse informazioni che hai registrato.'),
  ('mb_page.faq3_q', 'it', 'I membri del team possono modificare il Libro dei Ricordi?'),
  ('mb_page.faq3_a', 'it', 'Attualmente, solo il proprietario del team può creare e modificare le voci del Libro dei Ricordi. Tutti gli altri membri del team hanno accesso in sola lettura. Questo garantisce che il Libro dei Ricordi rimanga accurato e coerente, con una persona responsabile di mantenerlo aggiornato.'),
  ('mb_page.faq4_q', 'it', 'Il Libro dei Ricordi è una cartella clinica?'),
  ('mb_page.faq4_a', 'it', 'No. Il Libro dei Ricordi è un riferimento pratico per assistenti — non un documento clinico. Cattura informazioni che aiutano gli assistenti a fornire cure sicure, informate e personali. Per le cartelle cliniche formali, fai riferimento ai fornitori di assistenza sanitaria della tua persona cara.'),
  ('mb_page.faq5_q', 'it', 'Cosa succede se dimentico di compilare una sezione?'),
  ('mb_page.faq5_a', 'it', 'Il Libro dei Ricordi funziona con ciò che aggiungi. Le sezioni incomplete mostrano uno stato chiaro in modo che il proprietario del team sappia cosa è ancora necessario. Puoi costruirlo gradualmente — anche un Libro dei Ricordi parzialmente completato fornisce un valore significativo agli assistenti in ingresso.'),
  ('mb_page.faq6_q', 'it', 'Le informazioni della mia persona cara sono private e sicure?'),
  ('mb_page.faq6_a', 'it', 'Sì. Il Libro dei Ricordi è visibile solo ai membri del tuo team di cura — persone che hai esplicitamente invitato. È memorizzato in modo sicuro su un''infrastruttura crittografata. CarerView non condivide mai i tuoi dati con terze parti e mantieni la piena proprietà di tutte le informazioni che inserisci.'),
  ('mb_page.faq7_q', 'it', 'Il Libro dei Ricordi crescerà nel tempo?'),
  ('mb_page.faq7_a', 'it', 'Sì. Il Libro dei Ricordi attuale copre le quattro sezioni principali: Identità, Contatti, Medico e Preferenze. Gli aggiornamenti futuri aggiungeranno routine di Vita Quotidiana, Pasti, Attività, una sezione Comportamento & Sicurezza, un Diario personale e un Registro delle Modifiche. Le voci esistenti vengono conservate in tutti gli aggiornamenti.'),
  ('mb_page.cta_title', 'it', 'Inizia oggi a creare il Libro dei Ricordi della tua persona cara'),
  ('mb_page.cta_body', 'it', 'Crea un account gratuito ed esplora CarerView — o passa al piano Family Circle per sbloccare il Libro dei Ricordi e condividerlo con il tuo team di cura.')
INSERT INTO ui_translations (key, locale, value) VALUES
  ('nav.memory_book', 'sv', 'Varför din familj behöver en Minnesbok'),
  ('mb_page.eyebrow', 'sv', 'Minnesbok'),
  ('mb_page.hero_title', 'sv', 'Allt en vårdare behöver veta — på ett ställe'),
  ('mb_page.hero_body', 'sv', 'När en ny vårdare kommer in borde de inte behöva gissa. Minnesboken fångar vem din älskade är, vem man ska ringa, vad man ska se upp med och vad som ger dem tröst — delad omedelbart med alla i ditt vårdteam.'),
  ('mb_page.hero_cta_primary', 'sv', 'Bygg din Minnesbok'),
  ('mb_page.hero_cta_secondary', 'sv', 'Logga in'),
  ('mb_page.mock_title', 'sv', 'Se hur Minnesboken ser ut'),
  ('mb_page.mock_subtitle', 'sv', 'En levande omsorgsprofil som varje medlem i ditt team kan se i det ögonblick de ansluter sig.'),
  ('mb_page.mock_book_title', 'sv', 'Minnesbok'),
  ('mb_page.mock_tab_overview', 'sv', 'Översikt'),
  ('mb_page.mock_tab_identity', 'sv', 'Identitet'),
  ('mb_page.mock_tab_contacts', 'sv', 'Kontakter'),
  ('mb_page.mock_tab_medical', 'sv', 'Medicinsk'),
  ('mb_page.mock_tab_prefs', 'sv', 'Gillanden & Ogillandn'),
  ('mb_page.mock_identity_heading', 'sv', 'Identitet & Profil'),
  ('mb_page.mock_identity_sub', 'sv', 'Personliga uppgifter för Margareta H.'),
  ('mb_page.mock_edit_btn', 'sv', 'Redigera'),
  ('mb_page.mock_field_preferred_name', 'sv', 'Föredraget Namn'),
  ('mb_page.mock_field_address', 'sv', 'Hur man tilltalar'),
  ('mb_page.mock_field_birthplace', 'sv', 'Födelseort'),
  ('mb_page.mock_field_rel_status', 'sv', 'Civilstånd'),
  ('mb_page.mock_field_cultural', 'sv', 'Kulturell Bakgrund'),
  ('mb_page.mock_field_language', 'sv', 'Språkpreferenser'),
  ('mb_page.mock_field_about', 'sv', 'Om Mig'),
  ('mb_page.mock_about_text', 'sv', 'Margareta tillbringade 30 år som lärare i Edinburgh innan hon emigrerade med sin framlidne man Jakob. Hon har ett varmt, torrt sinne för humor och en djup kärlek till korsord, en god kopp te och berättelser om sina barnbarn.'),
  ('mb_page.mock_progress_label', 'sv', 'Minnesbokens Framsteg'),
  ('mb_page.mock_sections', 'sv', 'avsnitt klara'),
  ('mb_page.benefits_title', 'sv', 'Varför familjer förlitar sig på Minnesboken'),
  ('mb_page.benefits_subtitle', 'sv', 'Vårdteam fungerar bättre när alla har samma information från dag ett.'),
  ('mb_page.benefit1_title', 'sv', 'Omedelbart omsorgssammanhang'),
  ('mb_page.benefit1_body', 'sv', 'Varje ny vårdare — en avlösare, ett syskon på besök från utlandet — anländer med allt de behöver för att ge god omsorg från första ögonblicket.'),
  ('mb_page.benefit2_title', 'sv', 'Sluta leta efter nummer'),
  ('mb_page.benefit2_body', 'sv', 'Varje familjemedlem, läkare och nödkontakt på ett ställe. Hitta rätt person på sekunder, inte minuter.'),
  ('mb_page.benefit3_title', 'sv', 'Säkrare överlämningar'),
  ('mb_page.benefit3_body', 'sv', 'Medicinska anteckningar, allergier och omsorgsöverväganden alltid till hands. Informerade övergångar innebär färre luckor och färre risker.'),
  ('mb_page.benefit4_title', 'sv', 'Personlig värdighet'),
  ('mb_page.benefit4_body', 'sv', 'Bortom kliniska fakta fångar Minnesboken personen — deras historia, deras preferenser, vad som ger dem glädje. Omsorg blir mer än att bara slutföra uppgifter.'),
  ('mb_page.features_title', 'sv', 'Fyra avsnitt. En komplett bild.'),
  ('mb_page.features_subtitle', 'sv', 'Varje avsnitt är utformat kring verkliga omsorgssituationer — överlämningar, nödsituationer, nya teammedlemmar och vardaglig omsorg.'),
  ('mb_page.feat_identity_title', 'sv', 'Identitet & Personlig Profil'),
  ('mb_page.feat_identity_body', 'sv', 'Fånga vem din älskade är — inte bara deras namn, utan deras historia. Det här avsnittet hjälper varje vårdare att knyta an till personen bakom omsorgsplanen.'),
  ('mb_page.feat_identity_f1', 'sv', 'Föredraget namn och hur de vill bli tilltalade'),
  ('mb_page.feat_identity_f2', 'sv', 'Födelseort och kulturell bakgrund'),
  ('mb_page.feat_identity_f3', 'sv', 'Civilstånd'),
  ('mb_page.feat_identity_f4', 'sv', 'Språk- och kommunikationspreferenser'),
  ('mb_page.feat_identity_f5', 'sv', 'Personlig sammanfattning — med egna ord'),
  ('mb_page.feat_contacts_title', 'sv', 'Omsorgsnätverk & Kontakter'),
  ('mb_page.feat_contacts_body', 'sv', 'Lagra varje person i din älskades stödnätverk — familj, läkare, specialister och nödkontakter — var och en med sin roll, telefon, e-post och anteckningar.'),
  ('mb_page.feat_contacts_f1', 'sv', 'Familjemedlemmar och deras relation'),
  ('mb_page.feat_contacts_f2', 'sv', 'Husläkar- och specialistkontakter'),
  ('mb_page.feat_contacts_f3', 'sv', 'Grannar och samhällsstöd'),
  ('mb_page.feat_contacts_f4', 'sv', 'Rollmärken: huvudvårdare, nödsituation, medicinsk, annat'),
  ('mb_page.feat_medical_title', 'sv', 'Medicinskt Sammanhang'),
  ('mb_page.feat_medical_body', 'sv', 'Inte en klinisk akt — en praktisk referens för vårdare. Dokumentera vad hemvårdare och familjevårdare verkligen behöver veta för att ge säker, trygg omsorg.'),
  ('mb_page.feat_medical_f1', 'sv', 'Huvudsakliga tillstånd och diagnoser'),
  ('mb_page.feat_medical_f2', 'sv', 'Allergier (mat, läkemedel, miljö)'),
  ('mb_page.feat_medical_f3', 'sv', 'Hörsel- och synanteckningar'),
  ('mb_page.feat_medical_f4', 'sv', 'Aktuella läkemedel och administreringsanteckningar'),
  ('mb_page.feat_medical_f5', 'sv', 'Andra hälsoöverväganden för vårdare'),
  ('mb_page.feat_prefs_title', 'sv', 'Gillanden, Ogillandn & Tröst'),
  ('mb_page.feat_prefs_body', 'sv', 'Detaljerna som förvandlar omsorg från funktionell till personlig. Att veta vad som lugnar, vad man ska undvika och vad som framkallar ett äkta leende gör varje interaktion bättre.'),
  ('mb_page.feat_prefs_f1', 'sv', 'Aktiviteter, ämnen och upplevelser de gillar'),
  ('mb_page.feat_prefs_f2', 'sv', 'Matpreferenser och saker att undvika'),
  ('mb_page.feat_prefs_f3', 'sv', 'Musikpreferenser och favoritkonversationsämnen'),
  ('mb_page.feat_prefs_f4', 'sv', 'Vad som tröstar dem när de är upprörda'),
  ('mb_page.feat_prefs_f5', 'sv', 'Sensoriska preferenser och ångestutlösare'),
  ('mb_page.access_title', 'sv', 'Byggd för teamet. Synlig för alla.'),
  ('mb_page.access_body', 'sv', 'Teamägaren bygger Minnesboken. Varje vårdare du bjuder in — familjemedlemmar, hemarbetare eller stödpersoner — kan se den i det ögonblick de ansluter sig, utan konfiguration krävs.'),
  ('mb_page.access_cta', 'sv', 'Skapa ditt Gratiskonto'),
  ('mb_page.access_plans', 'sv', 'Visa Planer & Priser'),
  ('mb_page.personas_title', 'sv', 'Vem drar nytta av Minnesboken'),
  ('mb_page.personas_subtitle', 'sv', 'Från nattavlösaren som anländer för första gången till ett syskon som kollar in från utlandet.'),
  ('mb_page.persona1_title', 'sv', 'Nattavlösaren'),
  ('mb_page.persona1_quote', 'sv', '"Jag brukade frukta att täcka upp för en familj jag inte kände. Nu kollar jag Minnesboken innan jag anländer."'),
  ('mb_page.persona1_b1', 'sv', 'Känner till föredragna rutiner och sovtröst innan de går in'),
  ('mb_page.persona1_b2', 'sv', 'Kan hitta nödkontakter utan att väcka någon'),
  ('mb_page.persona1_b3', 'sv', 'Förstår läkemedelsbehov från den första natten'),
  ('mb_page.persona2_title', 'sv', 'Syskonet som återvänder från utlandet'),
  ('mb_page.persona2_quote', 'sv', '"Jag besöker två gånger om året och känner mig som en främling. Minnesboken stänger det gapet."'),
  ('mb_page.persona2_b1', 'sv', 'Hinner ikapp med medicinskt sammanhang utan en lång familjebriefing'),
  ('mb_page.persona2_b2', 'sv', 'Vet vad Mamma gillar nu kontra för ett år sedan'),
  ('mb_page.persona2_b3', 'sv', 'Kan hoppa in och hjälpa med självförtroende från dag ett'),
  ('mb_page.persona3_title', 'sv', 'Huvudvårdaren'),
  ('mb_page.persona3_quote', 'sv', '"Jag är minnesbankens. Minnesboken innebär att jag inte behöver förklara allt varje gång."'),
  ('mb_page.persona3_b1', 'sv', 'Dokumenterar allt en gång — inte ett dussin gånger'),
  ('mb_page.persona3_b2', 'sv', 'Delar omsorgsbördan utan att tappa kontrollen över noggrannheten'),
  ('mb_page.persona3_b3', 'sv', 'Minskar den känslomässiga bördan av konstant kommunikation'),
  ('mb_page.persona4_title', 'sv', 'Husläkaren eller samhällssjuksköterskan'),
  ('mb_page.persona4_quote', 'sv', '"Familjer som anländer organiserade hjälper oss att ge bättre omsorg."'),
  ('mb_page.persona4_b1', 'sv', 'Vårdare anländer till möten med tydliga, aktuella medicinska anteckningar'),
  ('mb_page.persona4_b2', 'sv', 'Allergier och tillstånd är dokumenterade, inte gissade'),
  ('mb_page.persona4_b3', 'sv', 'Kontakter är tillgängliga för samordnade omsorgssamtal'),
  ('mb_page.faq_title', 'sv', 'Vanliga Frågor'),
  ('mb_page.faq_subtitle', 'sv', 'Vanliga frågor om Minnesbok-funktionen.'),
  ('mb_page.faq1_q', 'sv', 'Vad är Minnesboken och vem kan se den?'),
  ('mb_page.faq1_a', 'sv', 'Minnesboken är en strukturerad omsorgsprofil för din älskade som täcker identitet, kontakter, medicinskt sammanhang och personliga preferenser. Det är en del av din CarerView Family Circle-plan. Teamägaren bygger och uppdaterar den. Varje teammedlem du bjuder in kan se hela Minnesboken så snart de ansluter sig — ingen separat installation krävs.'),
  ('mb_page.faq2_q', 'sv', 'Behöver jag Family Circle-planen för att använda Minnesboken?'),
  ('mb_page.faq2_a', 'sv', 'Ja. Minnesboken är en teamfunktion tillgänglig i Family Circle-planen. Den är utformad för att delas — så det ger mest mening när du har minst en annan vårdare eller familjemedlem i ditt team som drar nytta av att se samma information du har registrerat.'),
  ('mb_page.faq3_q', 'sv', 'Kan teammedlemmar redigera Minnesboken?'),
  ('mb_page.faq3_a', 'sv', 'För närvarande kan bara teamägaren skapa och redigera Minnesbok-poster. Alla andra teammedlemmar har läsbehörighet. Detta säkerställer att Minnesboken förblir korrekt och konsekvent, med en person ansvarig för att hålla den uppdaterad.'),
  ('mb_page.faq4_q', 'sv', 'Är Minnesboken ett medicinskt journal?'),
  ('mb_page.faq4_a', 'sv', 'Nej. Minnesboken är en praktisk referens för vårdare — inte ett kliniskt dokument. Den fångar information som hjälper vårdare att ge säker, informerad och personlig omsorg. För formella medicinska journaler, hänvisa till din älskades sjukvårdsleverantörer.'),
  ('mb_page.faq5_q', 'sv', 'Vad händer om jag glömmer att fylla i ett avsnitt?'),
  ('mb_page.faq5_a', 'sv', 'Minnesboken fungerar med det du lägger till. Ofullständiga avsnitt visar en tydlig status så att teamägaren vet vad som fortfarande behövs. Du kan bygga upp det gradvis — även en delvis ifylld Minnesbok ger betydande värde för inkommande vårdare.'),
  ('mb_page.faq6_q', 'sv', 'Är min älskades information privat och säker?'),
  ('mb_page.faq6_a', 'sv', 'Ja. Minnesboken är bara synlig för medlemmar i ditt vårdteam — personer som du uttryckligen har bjudit in. Den lagras säkert på krypterad infrastruktur. CarerView delar aldrig dina data med tredje part och du behåller fullt ägande av all information du anger.'),
  ('mb_page.faq7_q', 'sv', 'Kommer Minnesboken att växa med tiden?'),
  ('mb_page.faq7_a', 'sv', 'Ja. Den nuvarande Minnesboken täcker de fyra kärndelarna: Identitet, Kontakter, Medicinsk och Preferenser. Framtida uppdateringar kommer att lägga till Dagliga Livsrutiner, Måltider, Aktiviteter, ett Beteende & Säkerhetsavsnitt, en personlig Dagbok och en Ändringslogg. Befintliga poster bevaras vid alla uppdateringar.'),
  ('mb_page.cta_title', 'sv', 'Börja bygga din älskades Minnesbok idag'),
  ('mb_page.cta_body', 'sv', 'Skapa ett gratiskonto och utforska CarerView — eller uppgradera till Family Circle-planen för att låsa upp Minnesboken och dela den med ditt vårdteam.')
INSERT INTO ui_translations (key, locale, value) VALUES
  ('nav.memory_book', 'fi', 'Miksi perheesi tarvitsee Muistikirjan'),
  ('mb_page.eyebrow', 'fi', 'Muistikirja'),
  ('mb_page.hero_title', 'fi', 'Kaikki mitä hoitajan täytyy tietää — yhdessä paikassa'),
  ('mb_page.hero_body', 'fi', 'Kun uusi hoitaja saapuu, hänen ei pitäisi joutua arvailemaan. Muistikirja tallentaa kuka läheisesi on, keneen soittaa, mitä tarkkailla ja mikä tuo heille lohtua — jaettu välittömästi kaikille hoitotiimissäsi.'),
  ('mb_page.hero_cta_primary', 'fi', 'Rakenna Muistikirja'),
  ('mb_page.hero_cta_secondary', 'fi', 'Kirjaudu sisään'),
  ('mb_page.mock_title', 'fi', 'Katso miltä Muistikirja näyttää'),
  ('mb_page.mock_subtitle', 'fi', 'Elävä hoitoprofiili, jonka jokainen tiimisi jäsen voi nähdä heti liittyessään.'),
  ('mb_page.mock_book_title', 'fi', 'Muistikirja'),
  ('mb_page.mock_tab_overview', 'fi', 'Yleiskatsaus'),
  ('mb_page.mock_tab_identity', 'fi', 'Henkilöllisyys'),
  ('mb_page.mock_tab_contacts', 'fi', 'Yhteystiedot'),
  ('mb_page.mock_tab_medical', 'fi', 'Lääketieteellinen'),
  ('mb_page.mock_tab_prefs', 'fi', 'Mieltymykset'),
  ('mb_page.mock_identity_heading', 'fi', 'Henkilöllisyys & Profiili'),
  ('mb_page.mock_identity_sub', 'fi', 'Henkilökohtaiset tiedot: Margareetta H.'),
  ('mb_page.mock_edit_btn', 'fi', 'Muokkaa'),
  ('mb_page.mock_field_preferred_name', 'fi', 'Suosittu Nimi'),
  ('mb_page.mock_field_address', 'fi', 'Miten puhutella'),
  ('mb_page.mock_field_birthplace', 'fi', 'Syntymäpaikka'),
  ('mb_page.mock_field_rel_status', 'fi', 'Siviilisääty'),
  ('mb_page.mock_field_cultural', 'fi', 'Kulttuuritausta'),
  ('mb_page.mock_field_language', 'fi', 'Kielimieltymykset'),
  ('mb_page.mock_field_about', 'fi', 'Tietoa Minusta'),
  ('mb_page.mock_about_text', 'fi', 'Margareetta työskenteli 30 vuotta opettajana Edinburghissa ennen kuin hän muutti edesmenneen miehensä Jaakon kanssa. Hänellä on lämmin, kuiva huumorintaju ja syvä rakkaus ristisanoihin, hyvään kuppiin teetä ja tarinoihin lastenlapsistaan.'),
  ('mb_page.mock_progress_label', 'fi', 'Muistikirjan Edistyminen'),
  ('mb_page.mock_sections', 'fi', 'osiot valmiina'),
  ('mb_page.benefits_title', 'fi', 'Miksi perheet luottavat Muistikirjaan'),
  ('mb_page.benefits_subtitle', 'fi', 'Hoitotiimit toimivat paremmin, kun kaikilla on sama tieto ensimmäisestä päivästä lähtien.'),
  ('mb_page.benefit1_title', 'fi', 'Välitön hoitokonteksti'),
  ('mb_page.benefit1_body', 'fi', 'Jokainen uusi hoitaja — sijaishoitaja, ulkomailta vieraileva sisarus — saapuu kaiken tarvitsemansa kanssa tarjotakseen hyvää hoitoa ensimmäisestä hetkestä lähtien.'),
  ('mb_page.benefit2_title', 'fi', 'Ei enää numeroiden etsimistä'),
  ('mb_page.benefit2_body', 'fi', 'Jokainen perheenjäsen, lääkäri ja hätäkontakti yhdessä paikassa. Löydä oikea henkilö sekunneissa, ei minuuteissa.'),
  ('mb_page.benefit3_title', 'fi', 'Turvallisemmat siirtymät'),
  ('mb_page.benefit3_body', 'fi', 'Lääkinnälliset muistiinpanot, allergiat ja hoitonäkökohdat aina käsillä. Tietoiset siirtymät tarkoittavat vähemmän aukkoja ja vähemmän riskejä.'),
  ('mb_page.benefit4_title', 'fi', 'Henkilökohtainen arvokkuus'),
  ('mb_page.benefit4_body', 'fi', 'Kliinisten tosiseikkojen lisäksi Muistikirja tallentaa henkilön — hänen tarinansa, mieltymyksensä, mikä tuo hänelle iloa. Hoito muuttuu muuksi kuin pelkkien tehtävien suorittamiseksi.'),
  ('mb_page.features_title', 'fi', 'Neljä osiota. Täydellinen kuva.'),
  ('mb_page.features_subtitle', 'fi', 'Jokainen osio on suunniteltu todellisten hoitohetkien ympärille — siirtymät, hätätilanteet, uudet tiimin jäsenet ja jokapäiväinen hoito.'),
  ('mb_page.feat_identity_title', 'fi', 'Henkilöllisyys & Henkilökohtainen Profiili'),
  ('mb_page.feat_identity_body', 'fi', 'Tallenna kuka läheisesi on — ei vain hänen nimeään, vaan hänen tarinansa. Tämä osio auttaa jokaista hoitajaa yhdistymään hoitosuunnitelman takana olevaan henkilöön.'),
  ('mb_page.feat_identity_f1', 'fi', 'Suosittu nimi ja miten he haluavat tulla puhutelluksi'),
  ('mb_page.feat_identity_f2', 'fi', 'Syntymäpaikka ja kulttuuritausta'),
  ('mb_page.feat_identity_f3', 'fi', 'Siviilisääty'),
  ('mb_page.feat_identity_f4', 'fi', 'Kieli- ja viestintämieltymykset'),
  ('mb_page.feat_identity_f5', 'fi', 'Henkilökohtainen yhteenveto — omin sanoin'),
  ('mb_page.feat_contacts_title', 'fi', 'Hoitoverkosto & Yhteystiedot'),
  ('mb_page.feat_contacts_body', 'fi', 'Tallenna jokainen henkilö läheisesi tukiverkostossa — perhe, lääkärit, asiantuntijat ja hätäkontaktit — kukin rooleineen, puhelinnumeroineen, sähköposteineen ja muistiinpanoineen.'),
  ('mb_page.feat_contacts_f1', 'fi', 'Perheenjäsenet ja heidän suhteensa'),
  ('mb_page.feat_contacts_f2', 'fi', 'Yleislääkäri- ja asiantuntijakontaktit'),
  ('mb_page.feat_contacts_f3', 'fi', 'Naapurit ja yhteisötuki'),
  ('mb_page.feat_contacts_f4', 'fi', 'Roolimerkinnät: päähoitaja, hätätilanne, lääkinnällinen, muu'),
  ('mb_page.feat_medical_title', 'fi', 'Lääketieteellinen Konteksti'),
  ('mb_page.feat_medical_body', 'fi', 'Ei kliininen asiakirja — käytännöllinen hoitajan viite. Dokumentoi mitä kotihoitajat ja perhehoitajat todella tarvitsevat tietää tarjotakseen turvallista, luottavaista hoitoa.'),
  ('mb_page.feat_medical_f1', 'fi', 'Pääasiaiset sairaudet ja diagnoosit'),
  ('mb_page.feat_medical_f2', 'fi', 'Allergiat (ruoka, lääke, ympäristö)'),
  ('mb_page.feat_medical_f3', 'fi', 'Kuulo- ja näkömuistiinpanot'),
  ('mb_page.feat_medical_f4', 'fi', 'Nykyiset lääkkeet ja annostusohjeet'),
  ('mb_page.feat_medical_f5', 'fi', 'Muut hoitajille tärkeät terveysnäkökohdat'),
  ('mb_page.feat_prefs_title', 'fi', 'Tykkäykset, Inhokit & Lohdutukset'),
  ('mb_page.feat_prefs_body', 'fi', 'Yksityiskohdat, jotka muuttavat hoidon toiminnallisesta henkilökohtaiseksi. Tietää mikä rauhoittaa, mitä välttää ja mikä herättää aidon hymyn tekee jokaisesta vuorovaikutuksesta paremman.'),
  ('mb_page.feat_prefs_f1', 'fi', 'Toiminnot, aiheet ja kokemukset joista he nauttivat'),
  ('mb_page.feat_prefs_f2', 'fi', 'Ruokamieltymykset ja vältettävät asiat'),
  ('mb_page.feat_prefs_f3', 'fi', 'Musiikkimieltymykset ja suosikki keskusteluaiheet'),
  ('mb_page.feat_prefs_f4', 'fi', 'Mikä lohduttaa heitä kun he ovat järkyttyneitä'),
  ('mb_page.feat_prefs_f5', 'fi', 'Aistituntemukset ja ahdistuksen laukaisimet'),
  ('mb_page.access_title', 'fi', 'Rakennettu tiimille. Näkyvissä kaikille.'),
  ('mb_page.access_body', 'fi', 'Tiimin omistaja rakentaa Muistikirjan. Jokainen hoitaja jonka kutsut — perheenjäsenet, kotiavustajat tai tukihenkilöt — voi nähdä sen heti liittyessään, ilman asennusta.'),
  ('mb_page.access_cta', 'fi', 'Luo ilmainen tili'),
  ('mb_page.access_plans', 'fi', 'Katso Suunnitelmat & Hinnat'),
  ('mb_page.personas_title', 'fi', 'Kuka hyötyy Muistikirjasta'),
  ('mb_page.personas_subtitle', 'fi', 'Ensimmäistä kertaa saapuvasta yöhoitajasta ulkomailta tarkistavaan sisarukseen.'),
  ('mb_page.persona1_title', 'fi', 'Yösijaishoitaja'),
  ('mb_page.persona1_quote', 'fi', '"Minua pelotti ennen peittää perhe, jota en tuntenut. Nyt tarkistan Muistikirjan ennen saapumista."'),
  ('mb_page.persona1_b1', 'fi', 'Tietää suositut rutiinit ja nukkumaanmeno lohdut ennen sisään menoa'),
  ('mb_page.persona1_b2', 'fi', 'Löytää hätäkontaktit herättämättä ketään'),
  ('mb_page.persona1_b3', 'fi', 'Ymmärtää lääkinnälliset tarpeet ensimmäisestä yöstä lähtien'),
  ('mb_page.persona2_title', 'fi', 'Ulkomailta palaava sisarus'),
  ('mb_page.persona2_quote', 'fi', '"Vierailen kahdesti vuodessa ja tunnen olevani muukalainen. Muistikirja sulkee sen aukon."'),
  ('mb_page.persona2_b1', 'fi', 'Pääsee ajan tasalle lääketieteellisestä kontekstista ilman pitkää perhebriefingiä'),
  ('mb_page.persona2_b2', 'fi', 'Tietää mitä Äiti nauttii nyt verrattuna vuosi sitten'),
  ('mb_page.persona2_b3', 'fi', 'Voi astua sisään ja auttaa luottavaisesti ensimmäisestä päivästä lähtien'),
  ('mb_page.persona3_title', 'fi', 'Päähoitaja'),
  ('mb_page.persona3_quote', 'fi', '"Olen muistipankki. Muistikirja tarkoittaa että minun ei tarvitse selittää kaikkea joka kerta."'),
  ('mb_page.persona3_b1', 'fi', 'Dokumentoi kaiken kerran — ei tusinaa kertaa'),
  ('mb_page.persona3_b2', 'fi', 'Jakaa hoitotaakan menettämättä tarkkuuden hallintaa'),
  ('mb_page.persona3_b3', 'fi', 'Vähentää jatkuvan viestinnän tunnerasitusta'),
  ('mb_page.persona4_title', 'fi', 'Yleislääkäri tai yhteisöhoitaja'),
  ('mb_page.persona4_quote', 'fi', '"Perheet jotka saapuvat järjestyneesti auttavat meitä antamaan parempaa hoitoa."'),
  ('mb_page.persona4_b1', 'fi', 'Hoitajat saapuvat tapaamisiin selkeiden, ajankohtaisten lääkinnällisten muistiinpanojen kanssa'),
  ('mb_page.persona4_b2', 'fi', 'Allergiat ja sairaudet on dokumentoitu, ei arvattu'),
  ('mb_page.persona4_b3', 'fi', 'Yhteystiedot ovat saatavilla koordinoituja hoitokeskusteluja varten'),
  ('mb_page.faq_title', 'fi', 'Usein Kysytyt Kysymykset'),
  ('mb_page.faq_subtitle', 'fi', 'Yleisiä kysymyksiä Muistikirja-ominaisuudesta.'),
  ('mb_page.faq1_q', 'fi', 'Mikä on Muistikirja ja kuka voi nähdä sen?'),
  ('mb_page.faq1_a', 'fi', 'Muistikirja on strukturoitu hoitoprofiili läheisellesi, kattaen henkilöllisyyden, yhteystiedot, lääketieteellisen kontekstin ja henkilökohtaiset mieltymykset. Se on osa CarerView Family Circle -suunnitelmaasi. Tiimin omistaja rakentaa ja päivittää sen. Jokainen tiimin jäsen jonka kutsut voi nähdä koko Muistikirjan heti liittyessään — erillistä asennusta ei tarvita.'),
  ('mb_page.faq2_q', 'fi', 'Tarvitsenko Family Circle -suunnitelman Muistikirjan käyttöön?'),
  ('mb_page.faq2_a', 'fi', 'Kyllä. Muistikirja on tiimiominaisuus saatavilla Family Circle -suunnitelmassa. Se on suunniteltu jaettavaksi — joten siitä on eniten hyötyä kun sinulla on vähintään yksi muu hoitaja tai perheenjäsen tiimissäsi, joka hyötyy nähdessään samat tiedot jotka olet tallentanut.'),
  ('mb_page.faq3_q', 'fi', 'Voivatko tiimin jäsenet muokata Muistikirjaa?'),
  ('mb_page.faq3_a', 'fi', 'Tällä hetkellä vain tiimin omistaja voi luoda ja muokata Muistikirjan merkintöjä. Kaikilla muilla tiimin jäsenillä on vain lukuoikeus. Tämä varmistaa että Muistikirja pysyy tarkkana ja johdonmukaisena, yksi henkilö vastuussa sen päivittämisestä.'),
  ('mb_page.faq4_q', 'fi', 'Onko Muistikirja sairauskertomus?'),
  ('mb_page.faq4_a', 'fi', 'Ei. Muistikirja on käytännöllinen hoitajan viite — ei kliininen asiakirja. Se tallentaa tietoa joka auttaa hoitajia tarjoamaan turvallista, tietoista ja henkilökohtaista hoitoa. Virallisia sairauskertomuksia varten ota yhteyttä läheisesi terveydenhuollon tarjoajiin.'),
  ('mb_page.faq5_q', 'fi', 'Mitä tapahtuu jos unohdan täyttää osion?'),
  ('mb_page.faq5_a', 'fi', 'Muistikirja toimii sillä mitä lisäät. Epätäydelliset osiot näyttävät selkeän tilan jotta tiimin omistaja tietää mitä vielä tarvitaan. Voit rakentaa sen vähitellen — jopa osittain täytetty Muistikirja tarjoaa merkittävää arvoa saapuville hoitajille.'),
  ('mb_page.faq6_q', 'fi', 'Onko läheiseni tiedot yksityisiä ja turvallisia?'),
  ('mb_page.faq6_a', 'fi', 'Kyllä. Muistikirja on näkyvissä vain hoitotiimisi jäsenille — henkilöille jotka olet nimenomaisesti kutsunut. Se tallennetaan turvallisesti salattuun infrastruktuuriin. CarerView ei koskaan jaa tietojasi kolmansille osapuolille ja säilytät täyden omistajuuden kaikista syöttämistäsi tiedoista.'),
  ('mb_page.faq7_q', 'fi', 'Kasvaako Muistikirja ajan myötä?'),
  ('mb_page.faq7_a', 'fi', 'Kyllä. Nykyinen Muistikirja kattaa neljä ydinosaa: Henkilöllisyys, Yhteystiedot, Lääketieteellinen ja Mieltymykset. Tulevat päivitykset lisäävät Päivittäisen Elämän rutiineja, Aterioita, Aktiviteetteja, Käyttäytyminen & Turvallisuus -osion, henkilökohtaisen Päiväkirjan ja Muutoslokin. Olemassa olevat merkinnät säilytetään kaikissa päivityksissä.'),
  ('mb_page.cta_title', 'fi', 'Aloita rakentamaan läheisesi Muistikirjaa tänään'),
  ('mb_page.cta_body', 'fi', 'Luo ilmainen tili ja tutustu CarerViewiin — tai päivitä Family Circle -suunnitelmaan avataksesi Muistikirjan ja jakaaksesi sen hoitotiimisi kanssa.')
